import{_ as a,o as t,c as i,a3 as o}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"81. Qualification Allowance","description":"","frontmatter":{"title":"81. Qualification Allowance","eba":"Mental Health Services 2024-2028","topics":["allowances","preliminary"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/allowances/81-qualification-allowance.md","filePath":"ebas/mental-health/rpn-pen-mho/allowances/81-qualification-allowance.md"}'),n={name:"ebas/mental-health/rpn-pen-mho/allowances/81-qualification-allowance.md"};function l(r,e,s,c,h,p){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="_81-qualification-allowance" tabindex="-1">81. Qualification Allowance <a class="header-anchor" href="#_81-qualification-allowance" aria-label="Permalink to &quot;81. Qualification Allowance&quot;">​</a></h1><p>Note: see sub-<a href="/eba/ebas/mental-health/common-terms/preliminary/9-definitions.html">clause 9.1</a>(kk) (Definitions) regarding the interpretation of relevance.</p><p><strong>81.1</strong> Entitlement – Registered Psychiatrist Nurse</p><p><strong>(a)</strong> A Registered Psychiatric Nurse will be entitled to a qualification allowance, where an Employee has a:</p><p><strong>(i)</strong> relevant qualification (see 9.1(kk) (Definitions)) in addition to their base nursing or midwifery qualification.</p><p><strong>(ii)</strong> base qualification that is a double degree or master’s degree; or</p><p><strong>(iii)</strong> a Certificate IV in Training and Assessment.</p><p><strong>(b)</strong> In the case of the entitlement under subclause 81.1(a)(ii), the qualification allowance will be payable after one year of experience in an area where the qualification is relevant.</p><p><strong>(c)</strong> In the case of the entitlement under subclause 81.1(a)(iii), the qualification allowance will be payable only where the Employee is required by their Employer to hold a Certificate IV in Training and Assessment (or equivalent).</p><p><strong>81.2</strong> One Qualification Allowance Only</p><p>An Employee who has more than one qualification is entitled to one qualification allowance only, being the allowance for the highest qualification held for all ordinary hours worked, including where an Employee has multiple roles.</p><p><strong>81.3</strong> Evidence – Qualification held on commencement with Employer</p><p><strong>(a)</strong> An Employer must maintain a work system that requests the submission of evidence and records the qualification/s held by the Employee who commences after this Agreement comes into operation.</p><p><strong>(b)</strong> Where an Employee who commences after this Agreement comes into operation holds a relevant qualification as described at clause 81.1, the Employee will be entitled to payment from the commencement of Employment except where the Employee did not advise the Employer of the relevant qualification in accordance with the Employer’s work system including the provision of evidence.</p><p><strong>(c)</strong> The exception at (b) does not apply where:</p><p><strong>(i)</strong> The Employer did not maintain a work system as described at (a), or</p><p><strong>(ii)</strong> The Employer has otherwise recognised the relevant qualification such as by engaging the Employee in a position where the relevant qualification is mandatory.</p><p><strong>81.4</strong> Evidence – Qualifications obtained during Employment with Employer</p><p><strong>(a)</strong> An Employee claiming an entitlement to a qualification allowance must provide to the Employer evidence of that Employee having the qualification for which the entitlement is claimed.</p><p><strong>(b)</strong> An Employee claiming an entitlement to a qualification allowance will receive a substantive written response from the Employer (confirming its applicability or otherwise) within 28 days of the Employee complying with subclause 81.4(a).</p><p><strong>(c)</strong> An Employee will meet the evidence requirements described in subclause 81.4(a) when they have provided the Employer with evidence from the education / training provider that would satisfy a reasonable person that the Employee has obtained the qualification for which the allowance is claimed, for example:</p><p><strong>(i)</strong> the award of the qualification; or</p><p><strong>(ii)</strong> the certificate of the qualification; or</p><p><strong>(iii)</strong> transcript from the education/training provider, payable from the first pay period commencing on or after the evidence is provided.</p><p><strong>81.5</strong> Qualification Allowances - Registered Psychiatric Nurses A Registered Psychiatric Nurse shall be entitled to a qualification allowance under this clause will be paid, in addition to the Employee’s salary, as follows:</p><p><strong>(i)</strong> The rate - for &quot;RN Hospital/Grad Certificate&quot; in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> - for a Hospital Certificate or Graduate Certificate or equivalent. An equivalent may include a Certificate obtained from training or education facilities provider (such as infection control certificates from the Mayfield Centre) where the programmes are equivalent to a University Graduate Certificate and the training/education provider verifies that in writing.</p><p><strong>(ii)</strong> The rate for &quot;RN Post Grad Diploma or Degree&quot; in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> - for a Postgraduate Diploma, Degree or a Double Degree.</p><p><strong>(iii)</strong> The rate for &quot;RN Masters&quot; in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> - for a master’s degree.</p><p><strong>(iv)</strong> The rate for &quot;RN PhD&quot; in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> - for a Doctorate or a PhD.</p><p><strong>81.6</strong> Qualification allowance - Psychiatric Enrolled Nurses and Mental Health Officers</p><p><strong>(a)</strong> A qualification allowance applies to:</p><p><strong>(i)</strong> a PEN who holds a relevant certificate or qualification which, is in addition to the minimum qualification held by the PEN for registration with the NMBA; or</p><p><strong>(ii)</strong> a MHO who holds a certificate or qualification, in which it is demonstrated that at least one component is applicable to the Employee&#39;s current area of practice and/or work.</p><p><strong>(b)</strong> The allowance for a certificate or qualification (Including an Advanced Diploma in Mental Health) for a course of 6 months duration, but not including a pre or post registration course leading to endorsement to administer medication, is 4% of:</p><p><strong>(i)</strong> for a Level 1 PEN the &quot;EN1 6 MONTH COURSE&quot; in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>;</p><p><strong>(ii)</strong> for a Level 2 PEN the &quot;EN2 6 MONTH COURSE&quot; in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>;</p><p><strong>(iii)</strong> For a MHO, the &quot;MHO 6 MONTH COURSE&quot; in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> ;</p><p><strong>(c)</strong> The allowance for a certificate or qualification for a course of 12 months duration is 7.5% of:</p><p><strong>(i)</strong> for a level 1 PEN the &quot;EN1 12 MONTH COURSE&quot; in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>;</p><p><strong>(ii)</strong> for a level 2 PEN the &quot;EN2 12 MONTH COURSE&quot; in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>;</p><p><strong>(iii)</strong> for a MHO the &quot;MHO 12 MONTH COURSE&quot; in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a></p><p><strong>(d)</strong> Provided that only one allowance referred to above is payable to each PEN or MHO, being the allowance for the highest qualification held.</p><p><strong>(e)</strong> A PEN or a MHO claiming entitlements to the qualification allowance must provide the Employer with evidence that the qualification is actually held.</p><p><strong>(f)</strong> A qualification allowance cannot be claimed by a PEN in respect of that Employee&#39;s qualification leading to registration with the NMBA as a PEN.</p><p><strong>81.7</strong> Change of Ward An Employee in receipt of a qualification allowance who is relocated by the Employer including in accordance with <a href="/eba/ebas/mental-health/rpn-pen-mho/allowances/82-travelling-and-relocation-allowance.html">clause 82</a> (Travelling and Relocation) or <a href="/eba/ebas/mental-health/rpn-pen-mho/allowances/84A-change-of-ward-allowance.html">clause 84A</a> or 121A (Change of Ward Allowance) into an area where the qualification is not relevant, will continue to receive the qualification allowance.</p><p><strong>81.8</strong> Payment During Leave</p><p><strong>(a)</strong> Registered Nurse - the Qualification Allowances are to be paid on all periods of paid leave except sick leave beyond 21 days and long service leave.</p><p><strong>(b)</strong> Enrolled Nurse / MHO - the Qualification Allowance are to be paid during all periods of leave.</p><p><strong>81.9</strong> Pro rata entitlement The allowance is to be paid on a pro-rata basis for part time and casual Employees.</p><p><strong>81.10</strong> Certificate IV in Training and Assessment Allowance Rate The rate for &quot;Cert IV TAE Allowance&quot; as set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>.</p><p><strong>81.11</strong> Preservation of Advanced Diploma in Mental Health</p><p>Where an Employee holds an Advanced Diploma in Mental Health and is receiving a higher allowance rate than that within 81, the Employee will not be disadvantaged by the introduction of this Agreement.</p>',52)])])}const m=a(n,[["render",l]]);export{u as __pageData,m as default};
